Noticed this while writing docs:

```js
 {
    const anim = instance.new.animate(/* ... */);
    return () =&gt; {
      anim.cancel();
    };
  }}
  onExit={(instance) =&gt; {
    const anim = instance.new.animate(/* ... */);
    return () =&gt; {
      anim.cancel();
    };
  }}
&gt;
