Note these helpers:

```js
export function ClientWrapper({ children }: { children: ReactNode }) {
  const t = performance.now();
  while (performance.now() - t &lt; 2) {
    // do nothing
  }
  return &lt;&gt;{children}&lt;/&gt;;
}

function Resolved({ promise }: { promise: Promise&lt;ReactNode&gt; }) {
