  children,
}: {
  children: ReactNode;
}): Promise&lt;ReactNode&gt; {
  await new Promise((r) =&gt; setTimeout(r, 1));
  return children;
}

async function Item({ children }: { children: ReactNode }): Promise&lt;ReactNode&gt; {
  return (
    &lt;ClientWrapper&gt;
      &lt;AsyncChild&gt;{children}&lt;/AsyncChild&gt;
    &lt;/ClientWrapper&gt;
  );
}

export async function renderAction(input: string): Promise&lt;ReactNode&gt; {
